    """
    Calculates the nth Fibonacci number using memoization.
    fib(0) = 0, fib(1) = 1.
    """
    # Dictionary to store already computed Fibonacci numbers (the memoization table)
    memo = {}

    def fib_recursive(k):
        """
        Helper function to compute the k-th Fibonacci number using memoization.
        """
        if k in memo:
            return memo[k]

        if k == 0:
            return 0
        if k == 1:
            return 1

def binary_search(arr, target):
    left, right = 0, len(arr) - 1  # Correct initialization: right is the last index

    while left <= right:
        mid = (left + right) // 2

        if arr[mid] == target:
            return mid  # Target found
        elif arr[mid] < target:
            left = mid + 1  # Target must be in the right half
        else:
            right = mid - 1 # Target must be in the left half

    return -1  # Target not found

